var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"함선의 상황은?","JPN":"艦船の状況は？","ENG":"How's our ship doing?","TWN":"艦船的情況如何？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_EXCUTE_MASTER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"3번 보조 동력기관 작동 불가!","JPN":"3番補助動力機関作動不可！","ENG":"Its third auxiliary engine isn't working anymore.","TWN":"3號輔助動力機無法運作！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_EXCUTE_MASTER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"함선 무장 8할 소실! 다음 공격은 요격이 불가능합니다!","JPN":"艦船武装8割消失！　次の攻撃は迎撃できません！","ENG":"It's lost eighty percent of its armament. We can't intercept any more attacks!","TWN":"艦船武裝有8成毀損！無法攔截下一次的攻擊！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_EXCUTE_MASTER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"역시…… 연합 함대가 상대했을 때보다 더 강해졌어. ","JPN":"やはり……連合艦隊が相手した時よりもさらに強くなっている。","ENG":"I knew it... It's gotten stronger since it fought the Coalition Fleet. ","TWN":"果然……比那時候和聯合艦隊交手時變強許多！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_EXCUTE_MASTER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"급조한 부품으로 어떻게 저만큼 성능을 향상시켰지? 정말로 기계가 진화라도 하는 건가?","JPN":"急造した部品でどうやってあんなに性能を向上させられた？　本当に機械が進化でもするのか？","ENG":"How did they improve its performance so much with improvised components? Can that machine really evolve?","TWN":"是怎麼用粗製濫造的零件，把性能提升到這個程度的？真的是機械進化嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_EXCUTE_MASTER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"실장님! 마지막 호위함도 당했습니다! 이 이상은 위험합니다!","JPN":"室長！　最後の護衛艦もやられました！　これ以上は危険です！","ENG":"Chief! Our last escort ship went down! We're too vulnerable right now!","TWN":"室長！最後一艘護衛艦也快不行了！這樣下去會有危險！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_EXCUTE_MASTER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"이런……","JPN":"そんな……","ENG":"Oh, no...","TWN":"可惡……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_EXCUTE_MASTER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"선원들을 모두 대피시키세요! 함선은 포기합니다!","JPN":"船員たちを全員避難させてください！　艦船は諦めます！","ENG":"Evacuate everyone! We'll give up the ship!","TWN":"全員撤退！放棄艦船！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_EXCUTE_MASTER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"제 2파가 옵니다!","JPN":"第二波が来ます！","ENG":"Here comes the second wave!","TWN":"第2波來了！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_EXCUTE_MASTER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"방금 뭐였죠?","JPN":"今のは何でしょう？","ENG":"What was that?","TWN":"剛剛是怎麼回事？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"어서 상황 보고하세요!","JPN":"すみやかに状況を報告してください！","ENG":"Come on, tell me!","TWN":"立刻報告現況！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"놈이 기동을 멈췄습니다!","JPN":"奴の起動が止まりました！","ENG":"The robot stopped moving!","TWN":"那傢伙停止運作了！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"특수탄의 전자기 펄스를 직격으로 맞았어요!","JPN":"特殊弾の電磁パルスが直撃しました！","ENG":"It was hit by EMP from a special bullet!","TWN":"特殊彈的電磁脈衝正中紅心！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"네? 그렇다는 건……?","JPN":"え？　それはつまり……？","ENG":"What? That means...","TWN":"嗯？那就表示……？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>휴우, 아슬아슬했네요.</color>","JPN":"<color=#ffd34c>ふう、ギリギリでしたね。</color>","ENG":"<color=#ffd34c>Whew, that was close.</color>","TWN":"<color=#ffd34c>呼…真是驚險呢！</color>"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L35_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"다들 무사하시죠?","JPN":"みなさん、ご無事ですか？","ENG":"Is everyone okay?","TWN":"大家都平安嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨? 이볼브 원의 뒤를 잡으신 건가요?","JPN":"お嬢様？　イボルブ・ワンの裏を狙ったのですか？","ENG":"Miss Jia? Did you ambush the Evolved One from behind?","TWN":"小姐？是妳從Evolved One的身後攻擊她嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네, 키가 무척 큰 분이라 제가 오는 줄도 몰랐나 봐요.","JPN":"はい、とても大きい方だから私に気付かなかったかもしれませんね。","ENG":"Yes. the robot lady is so tall, didn't even know I was close.","TWN":"是的，她太高大了，所以沒察覺到我在她身後吧？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아, 코어를 찾았어요. 이걸 분리해서 가지고 가면 되는 거죠?","JPN":"あ、コアを見つけました。これを分離して持って行けばいいんですよね？","ENG":"Ah, found the core. You want me to separate it and take it with me, right?","TWN":"喔～找到核心了。把這個分離後帶走就可以了吧？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"그렇긴 합니다만…… 음?","JPN":"そうではありますが…… うん？","ENG":"Yes, but... Mm?","TWN":"是這樣沒錯……嗯？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아가씨! 조심하세요!","JPN":"お嬢様！　気をつけてください！","ENG":"Miss Jia, watch out!","TWN":"小姐小心！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_05"},{"id":"L47_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"What?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아윽…… 읏……","JPN":"あっ……うっ……","ENG":"Ugh... Aww...","TWN":"呃……嗚……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"내 장갑의 퇴화된 부분을 통해 유효한 타격을 입히다니.","JPN":"私の装甲の退化した部分を狙って、有効な打撃を与えるとは。","ENG":"You hit me in a degenerated opening in my armor.","TWN":"竟然利用我身上裝甲退化的部分進行攻擊…"},"stage":{"bg":"BLACK","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"알파트릭스의 어린 강아지 주제에 제법이군.","JPN":"アルファトリックスの子犬のくせに中々やるじゃないか。","ENG":"You're pretty good for a pup from Alphatrix.","TWN":"阿爾法崔克斯的小奶狗有兩下子嘛！"},"stage":{"bg":"BLACK","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"어떻게…… 움직이시는 거죠?","JPN":"どうして……動いているのですか？","ENG":"How... How are you moving?","TWN":"為什麼……妳還能動呢？"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"전자기 펄스는 적중했을 텐데……?","JPN":"電磁パルスが命中したはずなのに……？","ENG":"I hit you with an EMP.","TWN":"電磁脈衝不是有打中妳嗎……？"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"전자기 펄스.","JPN":"電磁パルス。","ENG":"EMP.","TWN":"電磁脈衝…"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"알파트릭스가 관리국과 손잡고 날 제압하는 데 사용했던 기술이지.","JPN":"アルファトリックスが管理局と手を組んで私を制圧する時に使っていた技術だ。","ENG":"Alphatrix used that technology to subdue me in concert with the Administration.","TWN":"就是阿爾法崔克斯和管理局聯手壓制我時，使用過的技術對吧？"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"일반적인 기계였다면 방금 그 공격으로 기동 불가 상태에 처했을 거다.","JPN":"一般的な機械であれば先ほどの攻撃で起動不可状態に陥ったはずだ。","ENG":"An ordinary machine would have been frozen by that attack.","TWN":"要是普通的機械受到剛剛的攻擊，肯定會無法運作。"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그리고 나를 일반적인 기계라고 판단한 것이, 너의 실책이다.","JPN":"そして私を一般的な機械と判断したことが、お前の失策だ。","ENG":"But I'm not ordinary. Thinking like that was your mistake.","TWN":"但如果妳以為我是普通的機械，那妳可就大錯特錯囉。"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"나는 이미, 극복했으니 말이다.","JPN":"私はすでに、克服している。","ENG":"I already have overcome that weakness.","TWN":"我已經…克服了！"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"극복……?","JPN":"克服……？","ENG":"Overcome?","TWN":"克服……？"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"장갑 증량. 배선 구조 교체. 방벽을 통한 전자기파 차폐.","JPN":"装甲増量。配線構造の取り替え。防壁による電磁波遮蔽。","ENG":"Increased armor. Updated wiring system. Anti-EMP barrier.","TWN":"裝甲增量、重新替換線路、透過屏障遮蔽電磁波。"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"나는 너희가 내게 바치는 기술의 산물을 통해 매순간 결함을 극복하고 강해지지.","JPN":"私はお前たちが私に捧げる技術の産物によって、毎瞬間欠陥を克服して強くなる。","ENG":"Every time you attack me with a new technology, I overcome my weaknesses and grow stronger.","TWN":"藉由你們在我身上進行研究後留下的結果，我每時每刻都在克服缺點不斷變強。"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그렇기에 나는, 진화 그 자체다.","JPN":"それ故私は、進化そのものだ。","ENG":"I'm evolution itself.","TWN":"因此，我本身就是進化！"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"할아버님께서 가르쳐 주셨어요.","JPN":"お祖父様に教えてもらいました。","ENG":"My grandfather told me.","TWN":"我爺爺說，"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"퓨처 앳 워는 현대의 한계를 뛰어넘어 미래의 기술을 연구하던 곳이지만……","JPN":"フューチャーアットウォーは現代の限界を超えて未来の技術を研究していましたが……","ENG":"Future-at-War used to study futuristic technologies to surpass the limits of the present.","TWN":"天啟兵器是一個突破現代極限，研究未來技術的地方……"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그 중에서도 유달리 먼 곳만 바라보던 과학자가 한 분 계셨다고요.","JPN":"その中でも、さらに先を見越していた科学者が一人いたそうです。","ENG":"And one of its scientists looked further than anyone else.","TWN":"在那裡，有一位野心特別大的科學家。"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"……할아버님이라.","JPN":"……お祖父様か。","ENG":"Your grandfather.","TWN":"妳爺爺是……"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"지금 그 모습이 된 건…… 저희 숙부님 때문인가요?","JPN":"今その姿になっているのは……叔父様が原因でしょうか？","ENG":"Did you become what you are now because of my uncle?","TWN":"妳現在會變成這樣……是因為我叔叔的關係嗎？"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"아니.","JPN":"いや。","ENG":"No.","TWN":"不。"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그 자는 과거에나 지금이나 그럴 능력이 없다.","JPN":"その者は過去も今もそのような実力はない。","ENG":"He was never good enough to have any influence over me.","TWN":"無論是過去或現在，他都沒有這樣的能力。"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"날 붙잡아 둔 채 샘플로 이용했으면서도 실패한 모조품이나 만드는 게 고작이었지.","JPN":"私を捕らえてサンプルとして利用しながらも、失敗した模造品を作るのが精一杯だった。","ENG":"He held me prisoner and used me as a testing sample, but all he could create were bad knock-offs.","TWN":"他把我抓來當樣品，卻只是製造出失敗的仿冒品。"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"이건, 오로지 나의 힘으로 이룩한 결과다.","JPN":"これは、己の力で成し遂げた成果だ。","ENG":"I've accomplished this on my own.","TWN":"我現在這個樣子，是唯有我有的力量才能產生的結果。"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그 과정에서 인간성과 함께 많은 것들을 내려놓아야 했지만……","JPN":"その過程で人間性とともに多くのものを手放さなければならなかったが……","ENG":"During the process, I had to give up many things, including my humanity, but...","TWN":"雖然在那樣的過程裡，必須拋棄掉許多人性面的東西……"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"충분히 그럴 만한 가치가 있었지.","JPN":"それだけの価値があった。","ENG":"It was worth the sacrifice.","TWN":"但這完全是有價值的。"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"통신이 회복됐습니다!","JPN":"通信が回復しました！","ENG":"Communications back online!","TWN":"恢復通訊了！"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L32_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>신지아 씨, 들리나요?</color>","JPN":"<color=#ffd34c>ヒメノ・ユイさん、聞こえますか？</color>","ENG":"<color=#ffd34c>Jia, can you hear me?</color>","TWN":"<color=#ffd34c>沈佳小姐，妳有聽到嗎？</color>"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L33_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>조금만 버티세요. 지금 가고 있습니다.</color>","JPN":"<color=#ffd34c>もう少し耐えてください。今向かっています。</color>","ENG":"<color=#ffd34c>Hang on just a little longer. We're coming.</color>","TWN":"<color=#ffd34c>妳再撐一下，我們正趕過去！</color>"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>이 자식들 완전 끈질기네! 저리 안 비켜?!</color>","JPN":"<color=#ffd34c>こいつら、しつこいな！　どけよ、こら！</color>","ENG":"<color=#ffd34c>These jerks are so persistent! Just go away!</color>","TWN":"<color=#ffd34c>這些傢伙有夠難纏的！都給我閃開啦！</color>"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>쏘, 쏩니다! 이젠 어떻게 되도 몰라요!</color>","JPN":"<color=#ffd34c>う、撃ちますよ！　もうどうなってもわかりませんよ！</color>","ENG":"<color=#ffd34c>I-I'm going to shoot! Don't blame me for whatever happens!</color>","TWN":"<color=#ffd34c>射…發射！死就死吧！</color>"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>아가씨!</color>","JPN":"<color=#ffd34c>お嬢様！</color>","ENG":"<color=#ffd34c>Miss Jia!</color>","TWN":"<color=#ffd34c>小姐！</color>"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>코핀 컴퍼니가 지원을 왔습니다! 복귀하지 않고 저희를 도우러 왔어요!</color>","JPN":"<color=#ffd34c>コフィンカンパニーの応援が来ました！　戻らず助けに来てくれました！</color>","ENG":"<color=#ffd34c>Coffin Company has arrived! Instead of leaving, it came to help us!</color>","TWN":"<color=#ffd34c>科芬公司的人來了！他們沒有回去，他們來幫我們了！</color>"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>지금 스캐빈저와 교전하면서 아가씨가 계신 곳으로 이동 중입니다! 조금만 버티세요!</color>","JPN":"<color=#ffd34c>今スカベンジャーと交戦しながらお嬢様がいる場所に移動中です！　もう少しだけ耐えてください！</color>","ENG":"<color=#ffd34c>It's fighting its way through the Scavengers to get where you are. Hang on!</color>","TWN":"<color=#ffd34c>我正一邊和清道夫交戰，一邊前往小姐所在的地方！請妳再撐一下！</color>"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……죄송해요.","JPN":"ごめんなさい……","ENG":"I'm sorry.","TWN":"很抱歉……"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"어떤 사정이 있는지는 모르겠지만, 전 당신을 여기서 쓰러트리고 돌아가야겠어요.","JPN":"どういう事情があるかわかりませんが、私はあなたをここで倒してから戻ります。","ENG":"I don't know what story you have, but I must bring you down and go back.","TWN":"我不清楚妳有什麼樣的苦衷，但我必須在這裡打倒妳。"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"다른 분들께 폐를 끼치지 말라고, 할아버님께서 가르쳐 주셨거든요.","JPN":"他の方々に迷惑はかけないようにと、お祖父様に教わったのです。","ENG":"Grandfather said I should never burden others.","TWN":"因為我爺爺說，不能給別人添麻煩。"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"회장은 성공했군. 나와 다르게.","JPN":"会長は成功したな。私と違って。","ENG":"So, the Chairman succeeded. Unlike me.","TWN":"會長成功了呢！"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네……?","JPN":"それは……？","ENG":"Pardon?","TWN":"什麼……？"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"너희를 전멸시키는 건 아주 간단한 일이다.","JPN":"お前たちを全滅させるのは、とても簡単なことだ。","ENG":"It'd be easy to wipe you out right here and now.","TWN":"我要把你們全殺光是輕而易舉的事。"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"하지만…… 어린 네가 앞으로 어떤 진화를 이루어낼지 흥미가 생기는군.","JPN":"しかし……幼いお前がこれからどういう進化を成し遂げるのか興味が湧いた。","ENG":"But... I'm interested in seeing how much you can evolve as a young human.","TWN":"不過……我很好奇，現在還年幼的妳，之後會進化成什麼樣子呢？"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"자비는 한 번뿐이다. ","JPN":"慈悲は一度だけだ。","ENG":"I won't be merciful again. ","TWN":"慈悲可只有一次。"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"돌아가라.","JPN":"……戻れ。","ENG":"Leave.","TWN":"這次暫且留妳一命！"},"stage":{"bg":"SS_SCAVENGER_01","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_30"},{"id":"L23_1","type":"dialog","speaker":"OPR_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>찾았습니다! 생명반응 확인!</color>","JPN":"<color=#ffd34c>見つけました！　生命反応確認！</color>","ENG":"<color=#ffd34c>Found her! Vital signs confirmed!</color>","TWN":"<color=#ffd34c>找到了！確認到生命反應！</color>"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>함선은 상공에서 대기하세요. 제가 아가씨를 모셔오는 대로 여길 벗어나야 합니다.</color>","JPN":"<color=#ffd34c>艦船は上空で待機してください。私がお嬢様を連れ戻し次第、ここを離れなければなりません。</color>","ENG":"<color=#ffd34c>Bridge, stand by in the air. We'll get out of here as soon as I pick up the Lady.</color>","TWN":"<color=#ffd34c>艦船在空中預備，等我把小姐帶出來就立刻離開這裡！</color>"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>아가씨, 괜찮으신가요?</color>","JPN":"<color=#ffd34c>お嬢様、大丈夫ですか？</color>","ENG":"<color=#ffd34c>Miss Jia, are you okay?</color>","TWN":"<color=#ffd34c>小姐，您沒事吧？</color>"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……전 괜찮아요, 이진 언니.","JPN":"……私は無事です、ホノカさん。","ENG":"I'm okay, Jin.","TWN":"……我沒事，李珍姐。"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"연구선은 되찾았으니, 저희 그만 돌아가요.","JPN":"研究船は取り戻しましたので、戻りましょう。","ENG":"Now that we've retrieved the research ship, we should leave.","TWN":"既然找到研究船了，那我們回去吧。"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"보고서는 확인했소.","JPN":"報告書を確認した。","ENG":"I read your report.","TWN":"報告我看完了。"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"아무래도 당신들은 넘버링 라이선스를 가지고 있을 만한 자격이 없는 것 같군.","JPN":"どうやらお前たちはナンバリングライセンスを持つ資格がないようだな。","ENG":"I don't think you deserve your numbered license.","TWN":"我看你們根本就只是徒有虛名吧？"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"텅 빈 연구선을 가져와 놓고 뻔뻔스럽게 보수를 청구하다니 말이야.","JPN":"空の研究船を持ってきて、厚かましく報酬を請求するなんて。","ENG":"You brought an empty research ship and have the audacity to ask for payment?","TWN":"帶回一艘空蕩蕩的研究船，還有臉要求支付酬勞？"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>스캐빈저에게 나포된 알파트릭스의 연구선을 회수한다.</color>","JPN":"<color=#ffd34c>スカベンジャーに拿捕されたアルファトリックスの研究船を回収する。</color>","ENG":"<color=#ffd34c>Retrieve Alphatrix's research ship from the Scavengers.</color>","TWN":"<color=#ffd34c>將阿爾法崔克斯集團被清道夫劫走的研究船搶回來。</color>"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당초의 계약 내용은 제대로 이행했습니다만.","JPN":"当初の契約内容はしっかり履行したはずです。","ENG":"I believe we've fulfilled our contract.","TWN":"當時的契約內容是這樣寫的，我應該沒有理解錯誤。"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"모르는 척 하지 마! 함선에 있던 이볼브 원의 코어를 해적 놈들한테 빼앗겼잖아!","JPN":"知らないふりをするな！　艦船のイボルブ・ワンのコアを海賊に奪われただろう！","ENG":"Don't pretend you don't know! You let the pirates steal the Evolved One's core from the ship!","TWN":"少跟我玩文字遊戲！研究船上的Evolved One核心，被那些海盜搶走了不是嗎！"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"게다가 그 안에 있던 다른 자료들은 전부 어디로 사라진 거지?!","JPN":"しかも他の資料は全てどこに消えたんだ！？","ENG":"And what about the other data? Where did they go?","TWN":"還有那裡面的其他資料呢？都到哪去了？！"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"먼저 말씀해 주시니 저희도 얘기하기 편하군요.","JPN":"先におっしゃってくださったので、こちら側も話しやすくなりました。","ENG":"Thank you for mentioning that before we do.","TWN":"既然您先提起這件事，那我就開門見山地說了！"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 안에 있는 연구 자료들 중에는 불법적인 종류도 상당히 섞여 있지 않았을까요?","JPN":"その中にある研究資料の中には、違法に当たる内容もかなり混ざっていたのではないでしょうか？","ENG":"What if a majority of the lost data was illegal?","TWN":"那些研究資料裡，其中也有許多不法的內容吧？"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"가령, 전량 압류되어야 했을 리플레이서 신디케이트의 연구 자료들이라거나 말이죠.","JPN":"たとえば、全て管理局に差し押さえられるはずのリプレイサー・シンジケートの研究資料など。","ENG":"Data about the Replacer Syndicate, which should have been turned in to the Administration, for example.","TWN":"我猜，那些是原本應該要被扣押的，克隆集團企業聯合組織研究資料吧？"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"……빌어먹을 것들 같으니.","JPN":"……狡猾極まりない連中め。","ENG":"You blasted pricks.","TWN":"……該死！"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"자료는 어쩔 셈이지?","JPN":"資料はどうするつもりだ？","ENG":"What are you going to do with that data?","TWN":"妳想拿那些資料做什麼？"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"경고해 두는데, 우리 그룹 연구 자료에 손가락 하나 댔다간 평생을 소송전으로 보내야 할 거야. ","JPN":"警告しておくが、我がグループの研究資料に指一本でも触れたら、一生訴訟戦に時間を費やされることになる。","ENG":"I warn you: you'd better not touch any of them, or you'll spend the rest of your life in court. ","TWN":"我可是警告妳，妳要是敢碰我們集團的研究資料，我一定會告死妳！"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"물론 저희가 회수한 분실물들은 곧 부회장님 집무실로 배송될 겁니다.","JPN":"もちろん弊社が回収した紛失物は、間もなく副会長の執務室に配送される予定です。","ENG":"All the lost assets we retrieved will be sent to your office, Mr. Vice Chairman.","TWN":"我們找回來的遺失物，很快就會送到副會長的辦公室。"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"애초에 멘탈 프린팅을 어설프게 흉내내려 한 실패일지에는 관심 없으니까요.","JPN":"そもそもメンタル・プリンティングを中途半端に真似した失敗記録には興味ありませんので。","ENG":"We're not interested in failed research about wasted attempts at imitating Mental Printing.","TWN":"反正我打從一開始，就對想要草率模仿智力複印的失敗日誌沒興趣。"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"……뭐? 무슨 소리지?","JPN":"……は？　どういうことだ？","ENG":"What? What are you talking about?","TWN":"……什？妳說什麼？"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"아니, 그보다 어떻게 멘탈 프린팅 기술에 대해 알고 있는 건가?","JPN":"いや、それよりどうしてメンタル・プリンティング技術について知っているんだ？","ENG":"Wait, how do you know about Mental Printing?","TWN":"妳怎麼會知道智力複印技術？"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그거야말로 그쪽이 신경 쓸 일이 아니지 않나요?","JPN":"それこそ御社に話す必要ない案件だと思いますが。","ENG":"That's none of your business, is it?","TWN":"我怎麼知道的不關您的事吧？"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"조만간 저희 사장님께서 연락드릴 예정이니 추가수당에 대해서나 생각해 두시죠.","JPN":"近いうちに弊社の社長から連絡する予定ですので、追加手当について事前に用意していただければと思います。","ENG":"My CEO will contact you soon. You'll have enough time to calculate our extra payment until then.","TWN":"我們老闆稍後會和您聯絡，應該是要跟您談額外的費用。"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EXECUTIVE_NPC_ALPHA_MAJOR","text":{"KOREA":"……사장?","JPN":"……社長？","ENG":"Your CEO?","TWN":"……老闆？"},"stage":{"bg":"SS_SCAVENGER_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흐음, 나한테 감사 인사를 하러 왔다고?","JPN":"ふむ、私にお礼を言いに来たと？","ENG":"Hm, you came to thank me?","TWN":"呵～妳是來謝我的嗎？ "},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네, 이번 작전 때 사장님의 친구 분을 통해서 선물을 받았거든요.","JPN":"はい、今回の作戦で社長の友人の方からプレゼントをいただいたのです。","ENG":"Yes. Your friend gave us a valuable gift during the last operation.","TWN":"是的，這次作戰時，老闆的朋友有送我一個禮物。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"덕분에 많은 도움이 됐어요.","JPN":"おかげで本当に助かりました。","ENG":"It helped us tremendously.","TWN":"這個禮物幫上許多忙呢！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이거, 별거 아니지만 답례로 받아주시겠어요?","JPN":"こちら、つまらないものですが受け取っていただけると幸いです。","ENG":"This is nothing, but I'd like to give it to you.","TWN":"這是一點點小心意，送給老闆作為謝禮。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오오옷! 이건 알파트릭스표 최고급 알칼라인 연료 전지!","JPN":"おおおっ！　これはアルファトリックス製最高級アルカリ燃料電池！","ENG":"Ooooh! Alphatrix's finest alkaline fuel batteries!","TWN":"哇哇哇！這是阿爾法崔克斯牌最高級的鹼性燃料電池欸！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자네, 물건 보는 안목이 좀 있구만!","JPN":"君、物を見る目があるな！","ENG":"You've got good taste!","TWN":"想不到妳滿會挑禮物的嘛！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"후훗. 좋아해 주셔서 저도 기뻐요.","JPN":"フフッ、喜んでもらえて私も嬉しいです。","ENG":"Heh heh. I'm glad you like them.","TWN":"呵呵～我也很開心你喜歡。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그리고 이건 파견을 나간 샤오린 씨를 위해 준비한 선물인데, 대신 전해 주시겠어요?","JPN":"そして、これはシャオリンさんのために用意したプレゼントなのですが、代わりに渡していただけませんか？","ENG":"And this is for Xiao Lin. Could you give it to her when she returns?","TWN":"另外這個是要送給曉琳的禮物，她現在正在派遣中吧？再麻煩老闆幫我轉交給她。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그야 물론이라네.","JPN":"もちろん。","ENG":"Of course.","TWN":"沒問題沒問題！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Mm?","TWN":"這是？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"……건강 야채 한 박스와 수면 안대?","JPN":"……超濃縮健康野菜ジュースと就寝用アイマスク？","ENG":"A box of healthy vegetables and a sleep mask?","TWN":"……健康養身蔬菜一箱和眼罩？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"샤오린 양이 이런 걸 좋아했던가?","JPN":"シャオリンはこういう物が好きだったかな？","ENG":"Did she like these sorts of things?","TWN":"曉琳喜歡這種東西喔？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"타이탄의 설계자를 찾는다고?","JPN":"タイタンの設計者を探していると？","ENG":"You're looking for the designer of the Titan?","TWN":"妳要找泰坦的設計人？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그래, 타이탄의 골조 설계와 동작 이론에 대한 정보가 필요해.","JPN":"そう、タイタンの骨組み設計と動作理論に関する情報が必要だ。","ENG":"Yes. I need information about the Titan's framework and theory of operation.","TWN":"對，我需要有關泰坦結構和動作理論的資料。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그런 거대한 로봇을 움직이는 건 내 개조만으론 어려운 일이거든.","JPN":"あんな巨大なロボットを動かすのは、私の改造技術だけじゃ難しくてね。","ENG":"I can modify machines, but I don't know how to move a big robot like this.","TWN":"光憑我的改造，是不可能讓那麼巨大的機器人動起來的。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"엠버 소장.","JPN":"アンバー所長。","ENG":"Director Ember.","TWN":"琥珀所長。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"너라면 그녀가 어디 있는지 알고 있겠지. ","JPN":"お前なら彼女がどこにいるかわかるだろ。","ENG":"You know where she is, don't you? ","TWN":"你應該知道她在哪裡吧？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"평의회의 이름으로 평소에도 온갖 정보를 수집하고 다니고 있잖아.","JPN":"評議会の名前を使って、普段からあらゆる情報を収集しているじゃないか。","ENG":"You're collecting all kinds of information in the name of the Council.","TWN":"你不是整天打著評議會的名義，到處收集資料嗎！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"의외로군. 그쪽이 기계도 아닌 사람에게 관심을 가질 줄은 몰랐어.","JPN":"意外だな。機械でもない人間に興味が湧いたとは。","ENG":"This is rather unexpected. I'd never thought you'd take an interest in anything that isn't a machine.","TWN":"真是意外，妳竟然會對人有興趣，我還以為妳眼裡只有機械。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"하지만 엠버 박사라…….","JPN":"しかしアンバー博士か……","ENG":"But Doctor Ember, huh?","TWN":"不過琥珀博士她……"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"그녀라면 퓨처 앳 워에서 제명된 이후 불법 반출된 아티팩트를 수소문했다는 기록이 있어.","JPN":"彼女ならフューチャーアットウォーから除名された後、違法搬出されたアーティファクトを探し回っていたという記録がある。","ENG":"There's a record of her looking for some illegally transferred Artifacts after she was expelled from Future-at-War.","TWN":"記錄顯示，自從她從天啟兵器中被除名後，就在打聽非法輸出的神器。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"그러다 마지막엔 소형선을 타고 혼자 이면세계로 떠난 뒤……","JPN":"そして最後は小型船に乗って、一人で裏世界に旅立った後……","ENG":"In the end, she took a small ship and left for the Counterside by herself.","TWN":"最後的記錄，是她搭著一艘小船獨自前往異界……"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"행방이 묘연해졌지.","JPN":"行方不明になった。","ENG":"She hasn't been seen since then.","TWN":"之後她便行蹤不明。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"구조 신호를 보낸 기록은 있는데, 결국 아무것도 발견되지 않았어.","JPN":"救助信号を送った記録はあるが、結局何も見つからなかった。","ENG":"There's a record of her sending rescue signals, but she was never found.","TWN":"雖然有發出求救訊號的記錄，結果卻沒有任何的發現。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"뭐야? 고작 그게 다라고?","JPN":"なんだ？　それしかないのか？","ENG":"What? That's it?","TWN":"搞什麼？就這樣嗎？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"술집 주정뱅이도 해 줄 것 같은 아무 영양가 없는 이야기잖아?","JPN":"酒場で飲みつぶれている奴からも聞けそうな、何の役にも立たない話だな？","ENG":"I could have just talked to some drunk at a bar and heard the same story.","TWN":"這些內容我隨便找個小酒館抓個醉漢來問，他都會告訴我吧？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"됐어. 나 혼자서 알아 봐야겠네.","JPN":"もういい。自分で調べる。","ENG":"Forget it. I'm going to find her on my own.","TWN":"真是沒用！我看我還是靠自己打聽吧！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"흐흠. 참을성 없는 건 여전하군. 조금만 더 들어 봐.","JPN":"ふっ。せっかちなのは相変わらずだな。もう少し人の話を聞け。","ENG":"Hah hah. You're as impatient as ever. I'm not finished.","TWN":"呵～妳還是一樣沒耐心呢！我話又還沒說完。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"신원으로 확인할 수 있는 정보는 이게 전부지만, 여기서부턴 논리적으로 접근해 보자고.","JPN":"確認できる情報はこれがすべてだが、ここからは論理的に考えてみよう。","ENG":"I told you everything I could learn based on her identity, but let's use logic from now on.","TWN":"以我的身份能打聽到的就是這些，但接下來才是精彩的地方，我要開始推理囉！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"일자리를 잃은 과학자의 발자취가 왜 하필 이면세계에서 끊겼는지 말이야.","JPN":"職を失った科学者の足跡が、なぜよりによって裏世界で途絶えたのか。","ENG":"Why would an unemployed scientist go to the Counterside of all places?","TWN":"妳想想，一個失業的科學家，為何足跡偏偏停留在異界呢？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"글쎄. 직장을 잃은 충격으로 어디 조용한 곳에서 혼자 죽으려 했나?","JPN":"さあな。仕事を失った衝撃で、どっか静かなところで一人で死のうとでもしたのか？","ENG":"I don't know. Maybe she was so upset about losing her job that she decided to kill herself somewhere quiet.","TWN":"我怎麼知道！可能是失業的打擊太大，她想找個沒人的地方結束生命吧？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"당연한 얘기지만, 이면세계엔 블랙 네트워크에도 없는 것들이 아주 많지.","JPN":"当たり前の話だが、裏世界にはブラックネットワークじゃ入手できないものがたくさん存在する。","ENG":"This is obvious, but the Counterside is filled with things that you can't find even on the Dark Network.","TWN":"妳說的也有道理，但異界可是有許多連黑色網絡也沒有的東西。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"엠버 박사가 만든 타이탄도 이면세계에서 발견된 메인 프레임으로 완성된 결과물이고.","JPN":"アンバー博士が作ったタイタンも、裏世界で発見されたメインフレームで完成したものだ。","ENG":"Her Titan's main frame was also discovered on the Counterside.","TWN":"琥珀博士創造的泰坦，也是利用在異界發現的大型主機製造而成的。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"박사는 다시 한 번 타이탄 같은…… 어쩌면 그보다 더 뛰어난 소재를 찾고 싶었을지도 몰라.","JPN":"博士はもう一度タイタンのような……もしかしたらそれよりもっと優れた素材を見つけたかったのかもしれない。","ENG":"Maybe Doctor Ember wanted to find another Titan... or something better.","TWN":"所以我猜，琥珀博士很可能是想再創造一個像泰坦一樣，不……甚至是比泰坦更厲害的機械，才會到異界去找材料。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그렇다고 일반인이 혼자 이면세계를 탐색한다는 건 그냥 죽겠다는 소리 아닌가?","JPN":"だからといって、一般人が一人で裏世界を探索するなんて自殺行為だろう。","ENG":"But you have to be suicidal to explore the Counterside by yourself when you're just an ordinary person.","TWN":"意思就是，她一個平凡人到異界找材料，然後她就死掉了？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"혼자인 편이 계획을 진행하기에 더 수월했을지도 모르지.","JPN":"一人の方が計画を進めるには楽だったのかもしれない。","ENG":"Maybe she had to be alone to carry out her plan.","TWN":"一個人說不定更好執行計畫呢！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"스캐빈저는 언제나 노예로 부릴 기술자들을 납치하고 다니잖아?","JPN":"スカベンジャーは頻繫に奴隷に使う技術者たちをさらっていくだろ？","ENG":"The Scavengers always look for technicians to abduct and enslave.","TWN":"清道夫不是一天到晚把研究人員綁架來當奴隸嗎？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"흠?","JPN":"ほう？","ENG":"Hmm?","TWN":"哦？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"녀석이 스캐빈저에게 일부러 납치당해 준 거라고?","JPN":"奴がスカベンジャーにわざとさらわれたと？","ENG":"You think she let the Scavengers abduct her, on purpose?","TWN":"你的意思是，她是故意被清道夫綁架的？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"기록에 따르면 말이지.","JPN":"記録によると、な。","ENG":"Record says...","TWN":"如果根據記錄的話啦！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"스캐빈저의 장비 수준이 어지간한 태스크포스를 뛰어넘기 시작한 것도 박사가 실종된 시기와 맞물려.","JPN":"スカベンジャーの装備水準が一般的なタスクフォースカンパニーを超え始めたのも、博士が失踪した時期と重なる。","ENG":"It was around the same time the doctor disappeared that the Scavengers started using gear that was better than most TASKFORCE companies'.","TWN":"清道夫的裝備水準開始超越特遣勢力的時間點，正好就是博士失蹤的時候！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"그리고 몇 년 뒤엔 스캐빈저에 커다란 기계 로봇이 나타나 우두머리 노릇을 하기 시작했고.","JPN":"そして、数年後にはスカベンジャーに巨大な機械ロボットが現れ、ボスとなっていた。","ENG":"Then, a few years later, a gigantic robot showed up leading the Scavengers.","TWN":"然後幾年後，清道夫中出現的巨大機器人開始成為老大。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"개인적인 이야기를 하나 하자면 난 내 아버지에게 세상에 우연 따위는 없다고 배웠지.","JPN":"個人的な話だが、私は自分の父から世の中に偶然なんて存在しないと教わった。","ENG":"This is just my story, but my dad told me nothing in this world is a coincidence.","TWN":"這是我私底下跟妳說的，我從我父親身上學到的就是，天底下沒有任何事情是偶然的！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"그리고 아주 오랫동안…… 그것이 진실이라는 걸 겪어야 했어.","JPN":"そしてとても長い間……それが真実であることをみずから経験してきた。","ENG":"And over the years, his lesson has proved itself true over and over again.","TWN":"而且經過我長時間以來的驗證……這句話是真的沒錯。"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"그러니 스캐빈저가 수집하는 유물과 기술을 이용하려고 일부러 납치당한 미치광이가 있다는 건……","JPN":"だから、スカベンジャーが収集する遺物と技術を利用しようと、わざと拉致されたイカれた人間がいるというのは……","ENG":"To me, it sounds plausible that some lunatic scientist let the Scavengers abduct her...","TWN":"也就是，有個想利用清道夫收集到的遺物和技術，才故意被綁架的瘋子……"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"내겐 아주 그럴 듯한 말로 들리는군. ","JPN":"私にはもっともらしい話に聞こえるね。","ENG":"because she wanted their Artifacts and technology. ","TWN":"根據我的理解是這樣啦！"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYSOP_NPC_NULL_NULL","text":{"KOREA":"……자네에겐 어떻지?","JPN":"……君はどう思う？","ENG":"What do you think?","TWN":"……妳怎麼看？"},"stage":{"bg":"HANGAR","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그땐 설마 정말로 그런 미치광이가 있을까 했는데.","JPN":"あの時はまさか本当にそんな変わり者がいるのかと半信半疑だったが。","ENG":"Back then, I didn't really believe him.","TWN":"那個時候，我還想說世界上真的有這種瘋子嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"큭큭, 그보다 더한 미치광이였을 줄은 몰랐네?","JPN":"ククク、それよりもさらに頭がおかしい人間だったとはね。","ENG":"Hah hah. And here, you're more lunatic than he thought.","TWN":"呵呵呵～沒想到瘋的程度還更厲害呢！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"만나서 반가워.","JPN":"会えて嬉しい。","ENG":"Nice to meet you.","TWN":"很高興見到妳，"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"엠버 박사.","JPN":"アンバー博士。","ENG":"Doctor Ember.","TWN":"琥珀博士。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"부하들로부터 대략의 전말은 파악했다.","JPN":"部下から聞いておおよその顛末は把握している。","ENG":"My men told me a brief story.","TWN":"我的手下有稍微跟我說一下來龍去脈，"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"날 찾아 온 이유가 무엇이지?","JPN":"私を訪ねた理由はなんだ？","ENG":"What do you want from me?","TWN":"妳找我要做什麼？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그냥 열성팬이 스타를 만나러 왔다고 생각해줘.","JPN":"お前の熱狂的なファンがスターに会いに来たという理由じゃダメかな。","ENG":"Let's say I'm an avid fan of yours.","TWN":"你就把我當作是追星的瘋狂粉絲吧。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"얼마 전에 당신의 작품을 체험할 기회가 있었거든.","JPN":"この前あんたの作品を体験する機会があったんだ。","ENG":"A while ago, I had a chance to experience your handiwork.","TWN":"之前我有幸體驗到妳的作品。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"덕분에, 그 날 이후로 다른 기계들로는 만족 못하게 됐지 뭐야?","JPN":"おかげで、あの日以来他の機械じゃ満足できない身体になってしまってね。","ENG":"And it's ruined other machines for me.","TWN":"托妳的福，從那之後任何機械都無法滿足我。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"……널 알고 있다. 기계수집가.","JPN":"……お前のことは知っている、機械収集家。","ENG":"I know you, Machine Collector.","TWN":"機械收藏家……我知道妳是誰。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"날 빼앗고 싶나?","JPN":"私を奪いたいのか？","ENG":"Do you want to collect me?","TWN":"妳想把我搶走？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"아니?","JPN":"いいや？","ENG":"No.","TWN":"不。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"처음엔 당연히 그러려고 했는데, 마음이 바뀌었어.","JPN":"最初はもちろんそうしようとしたが、気が変わった。","ENG":"At first, I did, but I've changed my mind.","TWN":"我原本是打算這樣沒錯，但我改變心意了。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"난 순수한 기계에 흥미가 있을 뿐이야.","JPN":"私は純粋に機械に興味があるだけ。","ENG":"I'm only interested in pure machines.","TWN":"我只對單純的機械有興趣。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"인간의 뇌를 스튜로 만들어서 회로에 끼얹은 너 같은 반쪽짜리는 취향이 아니지.","JPN":"人間の脳みそをシチューにして回路にぶっかけた、お前のような中途半端な奴は好みじゃない。","ENG":"Not the half-baked kind like you, whose circuits are drenched in human brain stew.","TWN":"像妳這種用人腦改造再加上線路的東西我沒興趣！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"유감이군.","JPN":"それは残念だ。","ENG":"How disappointing!","TWN":"真是遺憾！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"네가 날 공격하려 했다면, 널 미련없이 진화의 밑거름으로 썼을 텐데 말이지.","JPN":"お前が私を攻撃してきたなら、躊躇せずお前を進化の肥やしにしようとしたのだが。","ENG":"If you tried to attack me, I would have used you to further evolve myself without any qualms.","TWN":"妳要是攻擊我的話，我就可以把妳拿來當作進化的材料。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_TOUCH"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_05"},{"id":"L40_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"흥.","JPN":"ふん。","ENG":"Hmpf.","TWN":"哼。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"스캐빈저의 우두머리 자릴 되찾고 싶은 거라면 그냥 가져.","JPN":"スカベンジャーのボスという肩書きが欲しいなら、くれてやる。","ENG":"If you want the Scavengers' leadership position back, it's yours.","TWN":"如果妳是想奪回清道夫老大的位置，那就拿去吧！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"나도 뒤통수 노려보는 부하들은 필요 없으니까.","JPN":"俺だって隙ありゃ命を狙ってくる部下は要らねえ。","ENG":"I don't want to worry about being killed by my own men anymore.","TWN":"反正我也不想要一群整天想扯我後腿的手下！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그것보다 나한테 좋은 제안이 있는데…….","JPN":"それより、一つ提案があるんだが……","ENG":"By the way, I've got a proposition that you might be interested in.","TWN":"不過我有更好的提議……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"한 번 들어보겠어?","JPN":"聞いてみないか？","ENG":"Wanna hear it?","TWN":"妳要聽聽看嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"난 너와 같은 인간이 아니다.","JPN":"私はお前と同じ人間ではない。","ENG":"I'm not a human like you.","TWN":"我和妳不一樣。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"이 몸을 얻은 뒤로는 인간으로서의 일 따윈 아무래도 상관없어졌어.","JPN":"この身を手に入れた瞬間から、人間としての考え方なんてどうでもいいものになった。","ENG":"Since I've acquired this body, I stopped caring about human affairs.","TWN":"在我得到這副軀體後，人類的事情就已與我無關。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"신념이나 소원 같은 무가치한 것들은 <color=#ffd34c>나</color>라는 정의 앞에선 그저 말장난일 뿐이지.","JPN":"信念や願いのような無価値なものは、<color=#ffd34c>私</color>という正義の前では言葉遊びに過ぎない。","ENG":"Meaningless concepts like faith and belief are just wordplay in the face of the justice that is <color=#ffd34c>me</color>.","TWN":"信念或是心願這種話，在<color=#ffd34c>我</color>聽來不過就是沒意義的笑話而已。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"내 존재를 증명하는 것은 오직 영원한 진화 뿐이다.","JPN":"私の存在を証明するのはただ一つ、永遠の進化のみ。","ENG":"Only continuous evolution can prove my existence.","TWN":"能夠證明我的存在的，唯有永遠的進化而已！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"만약 그 제안에 인간다운 공감이 필요하다면 무의미한 시도가 되겠지.","JPN":"もしその提案に人間らしい共感が必要ならば、無意味な試みになるだろう。","ENG":"If your proposition requires human sympathy, it won't even be worth listening to.","TWN":"如果妳的提議是需要人性的回應，那我勸妳還是省點力氣吧！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그건 걱정 마.","JPN":"それは心配ないさ。","ENG":"Don't worry about that.","TWN":"妳先聽聽看再說嘛！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"분명 마음에 들 테니까.","JPN":"きっと気に入ると思う。","ENG":"It's worth listening to.","TWN":"妳一定會喜歡的！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"THEMA_SCAVANGER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"정비 끝났어, 깡통.","JPN":"整備が終わったぞ、ボロ缶。","ENG":"You're good to go, Tin Can.","TWN":"鐵桶，都修理好了！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_29"},{"id":"L8_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"으음.","JPN":"ううむ。","ENG":"Mm.","TWN":"嗯嗯。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"이야, 마취 하나 안 했는데 잘도 퍼질러자는구만.","JPN":"いやー、麻酔もしてないのによくそんな寝てられるな。","ENG":"Geez, how could you sleep without a drop of anesthetics in you?","TWN":"喂，我又沒給你打麻醉，你會不會睡得太爽？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"……뚫린 것만 메꾸랬더니, 또 뭔 짓을 한 거지?","JPN":"……空いた穴を埋めろと言ったはずなんだが、また何をしてくれたんだ？","ENG":"I asked you to just mend the holes. What did you do to me this time?","TWN":"……我叫你把破的地方補好就好，你又再給我亂弄什麼？！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"아, 좀 허전해 보이길래 심장을 하나 더 달았어.","JPN":"あ、ちょっと寂しく見えたから心臓をもう一つ付けてやったぞ。","ENG":"Ah, your chest looked so vacant that I added a heart.","TWN":"唉唷～看起來有點空虛嘛！我就又裝了顆心臟囉！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"살아 있는 거 보니, 작동엔 문제없어 보이네.","JPN":"まあ今生きているってことは、作動に問題はなさそうだな。","ENG":"You're still alive, so it must be working fine.","TWN":"我看你現在還有力氣罵人，那運作應該也沒問題吧！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"잘 모르겠군. 번거롭게 심장이 세 개씩이나 필요한 건가?","JPN":"よくわからんな。心臓なんて3つも必要なのか？　煩わしい。","ENG":"I don't know. Do I really need three hearts?","TWN":"我真猜不透你，有誰會需要三顆心臟？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"이번에 추가한 건 인공장기가 아니라 전자식이야. 그 여자가 쓰는 로봇 기생충이 꽤 쓸 만하더라고.","JPN":"今回追加したのは人工臓器じゃなくて電子式だ。あの女が使うロボット寄生虫が中々使えるもんでね。","ENG":"The one I've added this time isn't artificial; it's electrically-operated. That woman's robot parasites turned out to be pretty useful.","TWN":"這次裝的不是人工器官，是電子的好嗎！那女人使用的機器寄生蟲還滿不錯的嘛～"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"상처가 생기면 기생충이 혈류를 타고 흘러가서 빠르게 땜빵해 줄 거야.","JPN":"傷ができたら寄生虫が血流に乗って流れていき、素早く傷を埋めてくれる。","ENG":"Whenever you're wounded, the parasites will quickly flow through your bloodstream and mend you.","TWN":"有傷口的話，寄生蟲就會順著血液流動快速進行修補喔！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"목이 떨어져나가면……?","JPN":"首が吹っ飛ばされた時は……？","ENG":"But if you lose your head-","TWN":"但如果是頭掉了的話……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"그거야 어쩔 수 없겠지만.","JPN":"そりゃあどうにもならないな。","ENG":"I don't think they can put it back.","TWN":"那就…掰掰囉～"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"……그거.","JPN":"……それ。","ENG":"Well...","TWN":"嗯……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"아주 마음에 드는군.","JPN":"気に入ったぞ。","ENG":"I like that.","TWN":"我喜歡！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"깡통, 어디 가?","JPN":"ボロ缶、どこに行くんだ？","ENG":"Tin Can, where are you going?","TWN":"鐵桶，要去哪？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"어딜 가긴.","JPN":"どこに行くって？","ENG":"Do you have to ask?","TWN":"還能去哪！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"해적이 해적질하러 가지.","JPN":"海賊が海賊の仕事をしに行くに決まってんだろ。","ENG":"I'm a pirate. I'm going pirating.","TWN":"當然是要去幹些海盜會幹的事！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"새로운 심장도 테스트할 겸 해서 말이다.","JPN":"新しい心臓のテストも兼ねてな。","ENG":"I also want to test my new heart.","TWN":"順便測試一下新的心臟！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"아, 그거 좋지.","JPN":"お、それいいな。","ENG":"Ooo, that's a good idea!","TWN":"哦！不錯喔！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"테스트하고 싶은 게 지금 산더미처럼 쌓여 있던 참이거든.","JPN":"テストしたいことが山積みになっていたところだ。","ENG":"I've got plenty of stuff you can use to test.","TWN":"我現在想測試的東西堆得跟山一樣高呢！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};